  id: string;
  name: string;
  handle: string; // The username, should be `@username`
  avatarUrl: string;
  verified: boolean;
  public_metrics?: {
    followers_count: number;
    following_count: number;

    tweet_count: number;
    listed_count: number;
  };
}

