  id: string;
  content: string;
  author: XUserProfile;
  media?: {
    type: 'image' | 'video';
    url: string;
  };
  public_metrics: {
    retweet_count: number;
    reply_count: number;
    like_count: number;
    quote_count: number;
    impression_count: number; 
  };
