```typescript
import React, { useState, useRef, useEffect } from 'react';
import LogoIcon from './icons/LogoIcon';
import TextIcon from './icons/TextIcon';
import MediaIcon from './icons/MediaIcon';
import FolderIcon from './icons/FolderIcon';
import ChatHistoryPanel from './ChatHistoryPanel';
import type { Conversation, ActiveView } from '../types';

interface HeaderProps {
  activeView: ActiveView;
  setActiveView: (view: ActiveView) => void;
  conversations: Conversation[];
  activeConversationId: string | null;
  onSelectConversation: (id: string) => void;
  onNewConversation: () => void;
  onDeleteConversation: (id: string) => void;
}

const Header: React.FC<HeaderProps> = ({ 
  activeView, 
  setActiveView,
  conversations,
  activeConversationId,
  onSelectConversation,
  onNewConversation,
  onDeleteConversation
}) => {
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const historyRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const NavButton = ({ view, label, icon }: { view: ActiveView, label: string, icon: React.ReactNode }) => (
    <button
      onClick={() => setActiveView(view)}
      className={`flex items-center gap-2 px-3 py-2 rounded-full text-sm font-bold transition-colors ${
        activeView === view
          ? 'bg-white text-black shadow-md border border-black'
          : 'text-text-secondary hover:bg-white/10'
      }`}
    >
      {icon}
      <span className="hidden md:inline">{label}</span>
    </button>
  );

  return (
    <header className="fixed top-0 left-0 w-full bg-bg-primary/80 backdrop-blur-md border-b border-border-primary z-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-8 flex items-center justify-between h-20">
        <div className="flex items-center gap-3">
          <LogoIcon className="h-8 w-8" />
          <h1 className="text-xl font-bold text-text-primary">TwixAi</h1>
        </div>
        <nav className="flex items-center gap-4">
          {activeView === 'content' && (
            <div className="relative" ref={historyRef}>
              <button 
                onClick={() => setIsHistoryOpen(o => !o)} 
                className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-colors bg-white border border-black text-black hover:bg-slate-100 shadow-sm"
              >
                <FolderIcon className="h-5 w-5" />
                Historial
              </button>
              {isHistoryOpen && (
                <div className="absolute top-full right-0 mt-2 z-30 w-72 bg-white rounded-lg shadow-xl border border-slate-200">
                  <ChatHistoryPanel
                    conversations={conversations}
                    activeConversationId={activeConversationId}
                    onSelectConversation={(id) => {
                      onSelectConversation(id);
                      setIsHistoryOpen(false);
                    }}
                    onNewConversation={() => {
                      onNewConversation();
                      setIsHistoryOpen(false);
                    }}
                    onDeleteConversation={onDeleteConversation}
                  />
                </div>
              )}
            </div>
          )}
          <div className="flex items-center gap-1 p-1 bg-bg-secondary/50 rounded-full border border-border-primary">
            <NavButton view="content" label="Contenido" icon={<TextIcon className="h-5 w-5" />} />
            <NavButton view="multimedia" label="Multimedia" icon={<MediaIcon className="h-5 w-5" />} />
          </div>
        </nav>
      </div>
    </header>
  );
};

export default Header;
```

## App.tsx

Removed the imports and logic for Analytics, Scheduler, and LiveConversation to completely purge these features from the application logic.

```typescript
import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import { MultimediaCreator } from './components/MultimediaCreator';
import ChatBot from './components/ChatBot';
import Intro from './components/Intro';
import type { ActiveView, Conversation, ChatMessage, BrandVoiceProfile, Source } from './types';
import type { Chat, GenerateContentResponse } from "@google/genai";
import { createContentChatSession, withRetry, getFriendlyErrorMessage } from './services/geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ActiveView>('content');
  const [isLoading, setIsLoading] = useState(true);

  // State lifted from Dashboard
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const [brandVoiceProfile, setBrandVoiceProfile] = useState<BrandVoiceProfile | null>(null);
  const [isChatLoading, setIsChatLoading] = useState(false);

  // Effect to simulate initial loading screen
  useEffect(() => {
    setTimeout(() => setIsLoading(false), 1500);
  }, []);

  // Effect to load initial data from localStorage
  useEffect(() => {
    try {
        const savedProfile = localStorage.getItem('twixai-brand-voice');
        if (savedProfile) {
          setBrandVoiceProfile(JSON.parse(savedProfile));
        }
    } catch (error) {
        console.error("Failed to parse brand voice profile from localStorage", error);
        localStorage.removeItem('twixai-brand-voice');
    }

    try {
        const savedConvos = localStorage.getItem('twixai-chat-history');
        if (savedConvos) {
            const parsed = JSON.parse(savedConvos) as Conversation[];
            if (parsed.length > 0) {
                setConversations(parsed);
                setActiveConversationId(parsed.sort((a,b) => b.timestamp - a.timestamp)[0].id);
            } else {
                handleNewConversation();
            }
        } else {
            handleNewConversation();
        }
    } catch (error) {
        console.error("Failed to parse chat history from localStorage", error);
        localStorage.removeItem('twixai-chat-history');
        handleNewConversation();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
  }, [brandVoiceProfile]);

  useEffect(() => {
      if (conversations.length > 0) {
          localStorage.setItem('twixai-chat-history', JSON.stringify(conversations));
      }
  }, [conversations]);

  const handleSaveBrandVoice = (profile: BrandVoiceProfile) => {
    setBrandVoiceProfile(profile);
    localStorage.setItem('twixai-brand-voice', JSON.stringify(profile));
  };

  const handleNewConversation = () => {
    const newConvo: Conversation = {
        id: `convo-${Date.now()}`,
        title: 'Nuevo Chat',
        timestamp: Date.now(),
        messages: [
            { author: 'ai', content: "¡Hola! Soy tu asistente de IA para la creación de contenido. ¿Qué te gustaría crear hoy?" }
        ]
    };
    setConversations(prev => [newConvo, ...prev.filter(c => c.messages.length > 1 || c.title !== 'Nuevo Chat')]);
    setActiveConversationId(newConvo.id);
  };

  const handleSelectConversation = (id: string) => {
      setActiveConversationId(id);
  };

  const handleDeleteConversation = (id: string) => {
      const remainingConvos = conversations.filter(c => c.id !== id);
      setConversations(remainingConvos);
      if (activeConversationId === id) {
          if (remainingConvos.length > 0) {
              setActiveConversationId(remainingConvos.sort((a, b) => b.timestamp - a.timestamp)[0].id);
          } else {
              setActiveConversationId(null);
              handleNewConversation();
          }
      }
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }): Promise<string[]> => {
    if ((!message || message.trim() === '') && !file) return [];

    const userMessageContent = file ? `${message}\n\n[Archivo adjunto: ${file.name}]` : message;
    const userMessage: ChatMessage = { author: 'user', content: userMessageContent };

    let currentConvoId = activeConversationId;
    if (!currentConvoId) {
        const newConvo: Conversation = {
            id: `convo-${Date.now()}`,
            title: userMessage.content.substring(0, 40) + '...',
            timestamp: Date.now(),
            messages: [
                { author: 'ai', content: "¡Hola! Soy tu asistente de IA para la creación de contenido." },
                userMessage,
            ]
        };
        setConversations(prev => [newConvo, ...prev]);
        currentConvoId = newConvo.id;
        setActiveConversationId(newConvo.id);
    } else {
        setConversations(prev => prev.map(convo => 
            convo.id === currentConvoId ? { ...convo, messages: [...convo.messages, userMessage] } : convo
        ));
    }

    setIsChatLoading(true);

    try {
        if (!chatSession) throw new Error("La sesión de chat no está inicializada.");

        const parts: any[] = [{ text: message }];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }

        const response = await withRetry<GenerateContentResponse>(() =>
          chatSession.sendMessage({ message: parts })
        );
        const assistantResponse = response.text;
        const sources: Source[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk) || [];
        const aiMessage: ChatMessage = { 
            author: 'ai', 
            content: assistantResponse,
            sources: sources.length > 0 ? sources : undefined,
        };

        setConversations(prev => prev.map(convo => {
            if (convo.id === currentConvoId) {
                const newTitle = convo.title === 'Nuevo Chat' ? userMessage.content.substring(0, 40) + '...' : convo.title;
                return { ...convo, title: newTitle, messages: [...convo.messages, aiMessage] };
            }
            return convo;
        }));

        let parsedTweets: string[] = [];
        const isThread = assistantResponse.includes('"thread":');

        if (isThread) {
            try {
                let jsonStr = assistantResponse.trim();
                const jsonMatch = jsonStr.match(/```json\n?([\s\S]*?)\n?```/);
                if (jsonMatch && jsonMatch[1]) {
                    jsonStr = jsonMatch[1];
                } else {
                    const firstBrace = jsonStr.indexOf('{');
                    const lastBrace = jsonStr.lastIndexOf('}');
                    if (firstBrace !== -1 && lastBrace > firstBrace) {
                        jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
                    }
                }
                const result = JSON.parse(jsonStr);
                if (result.thread && Array.isArray(result.thread)) {
                    parsedTweets = result.thread;
                }
            } catch (e) {
                console.warn("La respuesta de la IA parecía un hilo pero no se pudo analizar:", e);
            }
        } else {
            let tweetContent = assistantResponse.trim();
            const prefixes = ["claro, aquí tienes un tuit:", "aquí tienes un tuit:", "claro, aquí tienes:", "aquí tienes:", "por supuesto, aquí tienes:", "aquí está el tuit:", "claro:", "¡claro!", "aquí está:"];
            for (const prefix of prefixes) {
                if (tweetContent.toLowerCase().startsWith(prefix)) {
                    tweetContent = tweetContent.substring(prefix.length).trim();
                    break; 
                }
            }
            const lines = tweetContent.split('\n');
            const firstNonEmptyLine = lines.find(l => l.trim() !== '');
            if (firstNonEmptyLine) {
                const isFirstLinePrefix = prefixes.some(p => firstNonEmptyLine.trim().toLowerCase() === p);
                if (isFirstLinePrefix) {
                    const contentStartIndex = lines.indexOf(firstNonEmptyLine) + 1;
                    tweetContent = lines.slice(contentStartIndex).join('\n').trim();
                }
            }
            if ((tweetContent.startsWith('"') && tweetContent.endsWith('"')) || (tweetContent.startsWith('“') && tweetContent.endsWith('”'))) {
                tweetContent = tweetContent.substring(1, tweetContent.length - 1).trim();
            }
            const isHelpResponse = tweetContent.length < 30 && /cómo|puedo|ayuda/i.test(tweetContent);
            if (tweetContent.length > 0 && !isHelpResponse) {
                parsedTweets = [tweetContent];
            }
        }
        return parsedTweets;
    } catch (error) {
       const errorMessage = getFriendlyErrorMessage(error, "obtener una respuesta de la IA");
       const errorAiMessage: ChatMessage = { author: 'ai', content: errorMessage };
       setConversations(prev => prev.map(convo => 
            convo.id === currentConvoId ? { ...convo, messages: [...convo.messages, errorAiMessage] } : convo
        ));
        return [];
    } finally {
        setIsChatLoading(false);
    }
  };

  const activeChatMessages = useMemo(() => {
    if (!activeConversationId) {
        const defaultMessages = [{
          author: 'ai' as const,
          content: "¡Hola! Soy tu asistente de IA para la creación de contenido. ¿Qué te gustaría crear hoy? Puedes pedirme un tuit, un hilo, o darme una idea y la desarrollaremos juntos."
        }];
        return defaultMessages;
    }
    return conversations.find(c => c.id === activeConversationId)?.messages || [];
  }, [conversations, activeConversationId]);

  const mainBgClass = 'bg-bg-primary';

  const renderActiveView = () => {
    switch (activeView) {
      case 'content':
        return <Dashboard 
          activeChatMessages={activeChatMessages}
          isChatLoading={isChatLoading}
          onSendMessage={handleSendMessage}
          onNewConversation={handleNewConversation}
          brandVoiceProfile={brandVoiceProfile}
          onSaveBrandVoice={handleSaveBrandVoice}
        />;
      case 'multimedia':
        return <MultimediaCreator />;
      default:
        return <Dashboard 
          activeChatMessages={activeChatMessages}
          isChatLoading={isChatLoading}
          onSendMessage={handleSendMessage}
          onNewConversation={handleNewConversation}
          brandVoiceProfile={brandVoiceProfile}
          onSaveBrandVoice={handleSaveBrandVoice}
        />;
    }
  };

  if (isLoading) {
    return <Intro />;
  }

  return (
    <div className={`min-h-screen ${mainBgClass} transition-colors duration-300`}>
      <Header 
        activeView={activeView} 
        setActiveView={setActiveView}
        conversations={conversations}
        activeConversationId={activeConversationId}
        onSelectConversation={handleSelectConversation}
        onNewConversation={handleNewConversation}
        onDeleteConversation={handleDeleteConversation}
      />
      <main className="pt-28 pb-8 px-4 sm:px-8">
        {renderActiveView()}
      </main>
      <ChatBot />
    </div>
  );
};

export default App;
```

## components/Dashboard.tsx

Removed the creation mode tabs ("Desde Texto", "Desde Enlace", etc.) to declutter the interface, leaving a clean Chat History view on the left and the Preview on the right.

```typescript
import React, { useState, useRef, useEffect } from 'react';
import { generateTweet, generateTweetThread, proofreadThread, summarizeUrl, summarizeFileContent, regenerateTweet, generateImage, createImagePromptFromTweet } from '../services/geminiService';
import type { XUserProfile, EditableTweet, BrandVoiceProfile, ChatMessage } from '../types';
import TweetPreview from './TweetPreview';
import SparklesIcon from './icons/SparklesIcon';
import PlusIcon from './icons/PlusIcon';
import GenerationStatus from './GenerationStatus';
import BrandVoiceModal from './BrandVoiceModal';
import ChatHistory from './ChatHistory';

const DEFAULT_USER_PROFILE: XUserProfile = {
  id: 'default-user',
  name: 'Tu Nombre',
  handle: '@tu_usuario',
  avatarUrl: `data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%2394A3B8'%3E%3Cpath d='M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z'/%3E%3C/svg%3E`,
  verified: false
};

interface DashboardProps {
  activeChatMessages: ChatMessage[];
  isChatLoading: boolean;
  onSendMessage: (message: string, file?: { data: string; mimeType: string; name: string }) => Promise<string[]>;
  onNewConversation: () => void;
  brandVoiceProfile: BrandVoiceProfile | null;
  onSaveBrandVoice: (profile: BrandVoiceProfile) => void;
}

const fileToBlob = (file: File): Promise<{data: string, mimeType: string, name: string}> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            // Basic fallback for mime types if empty (e.g. windows/md files sometimes)
            let mimeType = file.type;
            if (!mimeType) {
                if (file.name.endsWith('.md')) mimeType = 'text/markdown';
                if (file.name.endsWith('.txt')) mimeType = 'text/plain';
                if (file.name.endsWith('.csv')) mimeType = 'text/csv';
                if (file.name.endsWith('.json')) mimeType = 'application/json';
            }
            resolve({ data: result.split(',')[1], mimeType, name: file.name });
        };
        reader.onerror = error => reject(error);
    });
}

const Dashboard: React.FC<DashboardProps> = ({ activeChatMessages, isChatLoading, onSendMessage, onNewConversation, brandVoiceProfile, onSaveBrandVoice }) => {
  const [tweets, setTweets] = useState<EditableTweet[]>([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  const [isLoading, setIsLoading] = useState(false);
  const [generationStatus, setGenerationStatus] = useState<{ title: string; steps: string[]; currentStep: number; error: string | null; } | null>(null);

  const [isBrandVoiceModalOpen, setIsBrandVoiceModalOpen] = useState(false);

  const [isMediaPromptModalOpen, setIsMediaPromptModalOpen] = useState(false);
  const [mediaPrompt, setMediaPrompt] = useState('');
  const [mediaAspectRatio, setMediaAspectRatio] = useState('16:9');
  const [mediaGenerationTarget, setMediaGenerationTarget] = useState<{type: 'image', index: number} | null>(null);
  const [apiError, setApiError] = useState<string | null>(null);

  const mediaFileInputRef = useRef<HTMLInputElement>(null);
  const [mediaTargetIndex, setMediaTargetIndex] = useState<number | null>(null);
  const tweetPreviewRefs = useRef<(HTMLDivElement | null)[]>([]);

  const effectiveUserProfile = DEFAULT_USER_PROFILE;

  const handleTweetChange = (index: number, value: string) => {
    const newTweets = [...tweets];
    newTweets[index].content = value;
    setTweets(newTweets);
  };

  const addTweetToThread = () => {
    setTweets([...tweets, { id: `tweet-${Date.now()}`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  };

    const handleNewCreation = () => {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
      onNewConversation();
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }) => {
    const parsedTweets = await onSendMessage(message, file);

    if (parsedTweets.length > 0) {
        setTweets(parsedTweets.map((content, i) => ({
            id: `tweet-${Date.now()}-${i}`,
            content,
            media: null,
            isLoadingMedia: false,
            isCopied: false,
            isRegenerating: false,
        })));
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setTweets(prevTweets => {
        const newTweets = [...prevTweets];
        newTweets[index] = {...newTweets[index], isCopied: true};
        return newTweets;
      });
      setTimeout(() => {
        setTweets(prevTweets => {
          const resetTweets = [...prevTweets];
          resetTweets[index] = {...resetTweets[index], isCopied: false};
          return resetTweets;
        });
      }, 2000);
    });
  };

  const handleRegenerateTweet = async (index: number) => {
    const originalTweet = tweets[index];
    if (!originalTweet || originalTweet.content.trim() === '') return;

    setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: true } : t));

    try {
        const regeneratedContent = await regenerateTweet(originalTweet.content);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, content: regeneratedContent, isRegenerating: false } : t));
    } catch (error) {
        console.error("Error al regenerar el tuit:", error);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: false } : t));
    }
  };

  const handleDeleteTweet = (index: number) => {
    if (tweets.length === 1) {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    } else {
      setTweets(prevTweets => prevTweets.filter((_, i) => i !== index));
    }
  };

    const closeMediaPromptModal = () => {
        setIsMediaPromptModalOpen(false);
        setMediaPrompt('');
        setMediaGenerationTarget(null);
    };

    const handleConfirmMediaGeneration = async () => {
        if (!mediaGenerationTarget || !mediaPrompt) return;

        const { index } = mediaGenerationTarget;
        closeMediaPromptModal();

        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: true } : t));
        try {
            const { images } = await generateImage(mediaPrompt, mediaAspectRatio);
            if (images.length > 0) {
                const mediaUrl = `data:image/jpeg;base64,${images[0]}`;
                setTweets(prev => prev.map((t, i) => i === index ? { ...t, media: { type: 'image', url: mediaUrl }, isLoadingMedia: false } : t));
            } else {
                throw new Error("La IA no generó una imagen.");
            }
        } catch (error) {
            const message = error instanceof Error ? error.message : "Error al generar la imagen. Por favor, inténtalo de nuevo.";
            setApiError(message);
            setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: false } : t));
        }
    };

    const handleGenerateMedia = async (index: number) => {
        const tweetContent = tweets[index]?.content;
        if (!tweetContent) {
            setApiError("Por favor, escribe algo en el tuit para generar una imagen.");
            return;
        }

        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: true } : t));
        try {
            const imagePrompt = await createImagePromptFromTweet(tweetContent);
            setMediaPrompt(imagePrompt);
            setMediaGenerationTarget({ type: 'image', index });
            setMediaAspectRatio('16:9'); // Default aspect ratio
            setIsMediaPromptModalOpen(true);
