```typescript
import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import { MultimediaCreator } from './components/MultimediaCreator';
import ChatBot from './components/ChatBot';
import Intro from './components/Intro';
import type { ActiveView, Conversation, ChatMessage, BrandVoiceProfile, Source } from './types';
import type { Chat, GenerateContentResponse } from "@google/genai";
import { createContentChatSession, withRetry, getFriendlyErrorMessage } from './services/geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ActiveView>('content');
  const [isLoading, setIsLoading] = useState(true);

  // State lifted from Dashboard
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const [brandVoiceProfile, setBrandVoiceProfile] = useState<BrandVoiceProfile | null>(null);
  const [isChatLoading, setIsChatLoading] = useState(false);

  // Effect to simulate initial loading screen
  useEffect(() => {
    setTimeout(() => setIsLoading(false), 1500);
  }, []);

  // Effect to load initial data from localStorage
  useEffect(() => {
    try {
        const savedProfile = localStorage.getItem('twixai-brand-voice');
        if (savedProfile) {
          setBrandVoiceProfile(JSON.parse(savedProfile));
        }
    } catch (error) {
        console.error("Failed to parse brand voice profile from localStorage", error);
        localStorage.removeItem('twixai-brand-voice');
    }

    try {
        const savedConvos = localStorage.getItem('twixai-chat-history');
        if (savedConvos) {
            const parsed = JSON.parse(savedConvos) as Conversation[];
            if (parsed.length > 0) {
                setConversations(parsed);
                setActiveConversationId(parsed.sort((a,b) => b.timestamp - a.timestamp)[0].id);
            } else {
                handleNewConversation();
            }
        } else {
            handleNewConversation();
        }
    } catch (error) {
        console.error("Failed to parse chat history from localStorage", error);
        localStorage.removeItem('twixai-chat-history');
        handleNewConversation();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
  }, [brandVoiceProfile]);

  useEffect(() => {
      if (conversations.length > 0) {
          localStorage.setItem('twixai-chat-history', JSON.stringify(conversations));
      }
  }, [conversations]);

  const handleSaveBrandVoice = (profile: BrandVoiceProfile) => {
    setBrandVoiceProfile(profile);
    localStorage.setItem('twixai-brand-voice', JSON.stringify(profile));
  };

  const handleNewConversation = () => {
    const newConvo: Conversation = {
        id: `convo-${Date.now()}`,
        title: 'Nuevo Chat',
        timestamp: Date.now(),
        messages: [
            { author: 'ai', content: "¡Hola! Soy tu asistente de IA para la creación de contenido. ¿Qué te gustaría crear hoy?" }
        ]
    };
    setConversations(prev => [newConvo, ...prev.filter(c => c.messages.length > 1 || c.title !== 'Nuevo Chat')]);
    setActiveConversationId(newConvo.id);
  };

  const handleSelectConversation = (id: string) => {
      setActiveConversationId(id);
  };

  const handleDeleteConversation = (id: string) => {
      const remainingConvos = conversations.filter(c => c.id !== id);
      setConversations(remainingConvos);
      if (activeConversationId === id) {
          if (remainingConvos.length > 0) {
              setActiveConversationId(remainingConvos.sort((a, b) => b.timestamp - a.timestamp)[0].id);
          } else {
              setActiveConversationId(null);
              handleNewConversation();
          }
      }
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }): Promise<string[]> => {
    if ((!message || message.trim() === '') && !file) return [];

    const userMessageContent = file ? `${message}\n\n[Archivo adjunto: ${file.name}]` : message;
    const userMessage: ChatMessage = { author: 'user', content: userMessageContent };

    let currentConvoId = activeConversationId;
    if (!currentConvoId) {
        const newConvo: Conversation = {
            id: `convo-${Date.now()}`,
            title: userMessage.content.substring(0, 40) + '...',
            timestamp: Date.now(),
            messages: [
                { author: 'ai', content: "¡Hola! Soy tu asistente de IA para la creación de contenido." },
                userMessage,
            ]
        };
        setConversations(prev => [newConvo, ...prev]);
        currentConvoId = newConvo.id;
        setActiveConversationId(newConvo.id);
    } else {
        setConversations(prev => prev.map(convo => 
            convo.id === currentConvoId ? { ...convo, messages: [...convo.messages, userMessage] } : convo
        ));
    }

    setIsChatLoading(true);

    try {
        if (!chatSession) throw new Error("La sesión de chat no está inicializada.");

        const parts: any[] = [{ text: message }];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }

        const response = await withRetry<GenerateContentResponse>(() =>
          chatSession.sendMessage({ message: parts })
        );
        const assistantResponse = response.text;
        const sources: Source[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk) || [];
        const aiMessage: ChatMessage = { 
            author: 'ai', 
            content: assistantResponse,
            sources: sources.length > 0 ? sources : undefined,
        };

        setConversations(prev => prev.map(convo => {
            if (convo.id === currentConvoId) {
                const newTitle = convo.title === 'Nuevo Chat' ? userMessage.content.substring(0, 40) + '...' : convo.title;
                return { ...convo, title: newTitle, messages: [...convo.messages, aiMessage] };
            }
            return convo;
        }));

        let parsedTweets: string[] = [];
        const isThread = assistantResponse.includes('"thread":');

        if (isThread) {
            try {
                let jsonStr = assistantResponse.trim();
                const jsonMatch = jsonStr.match(/```json\n?([\s\S]*?)\n?```/);
                if (jsonMatch && jsonMatch[1]) {
                    jsonStr = jsonMatch[1];
                } else {
                    const firstBrace = jsonStr.indexOf('{');
                    const lastBrace = jsonStr.lastIndexOf('}');
                    if (firstBrace !== -1 && lastBrace > firstBrace) {
                        jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
                    }
                }
                const result = JSON.parse(jsonStr);
                if (result.thread && Array.isArray(result.thread)) {
                    parsedTweets = result.thread;
                }
            } catch (e) {
                console.warn("La respuesta de la IA parecía un hilo pero no se pudo analizar:", e);
            }
        } else {
            let tweetContent = assistantResponse.trim();
            const prefixes = ["claro, aquí tienes un tuit:", "aquí tienes un tuit:", "claro, aquí tienes:", "aquí tienes:", "por supuesto, aquí tienes:", "aquí está el tuit:", "claro:", "¡claro!", "aquí está:"];
            for (const prefix of prefixes) {
                if (tweetContent.toLowerCase().startsWith(prefix)) {
                    tweetContent = tweetContent.substring(prefix.length).trim();
                    break; 
                }
            }
            const lines = tweetContent.split('\n');
            const firstNonEmptyLine = lines.find(l => l.trim() !== '');
            if (firstNonEmptyLine) {
                const isFirstLinePrefix = prefixes.some(p => firstNonEmptyLine.trim().toLowerCase() === p);
                if (isFirstLinePrefix) {
                    const contentStartIndex = lines.indexOf(firstNonEmptyLine) + 1;
                    tweetContent = lines.slice(contentStartIndex).join('\n').trim();
                }
            }
            if ((tweetContent.startsWith('"') && tweetContent.endsWith('"')) || (tweetContent.startsWith('“') && tweetContent.endsWith('”'))) {
                tweetContent = tweetContent.substring(1, tweetContent.length - 1).trim();
            }
            const isHelpResponse = tweetContent.length < 30 && /cómo|puedo|ayuda/i.test(tweetContent);
            if (tweetContent.length > 0 && !isHelpResponse) {
                parsedTweets = [tweetContent];
            }
        }
        return parsedTweets;
    } catch (error) {
       const errorMessage = getFriendlyErrorMessage(error, "obtener una respuesta de la IA");
       const errorAiMessage: ChatMessage = { author: 'ai', content: errorMessage };
       setConversations(prev => prev.map(convo => 
            convo.id === currentConvoId ? { ...convo, messages: [...convo.messages, errorAiMessage] } : convo
        ));
        return [];
    } finally {
        setIsChatLoading(false);
    }
  };

  const activeChatMessages = useMemo(() => {
    if (!activeConversationId) {
        const defaultMessages = [{
          author: 'ai' as const,
          content: "¡Hola! Soy tu asistente de IA para la creación de contenido. ¿Qué te gustaría crear hoy? Puedes pedirme un tuit, un hilo, o darme una idea y la desarrollaremos juntos."
        }];
        return defaultMessages;
    }
    return conversations.find(c => c.id === activeConversationId)?.messages || [];
  }, [conversations, activeConversationId]);

  const mainBgClass = 'bg-bg-primary';

  const renderActiveView = () => {
    switch (activeView) {
      case 'content':
        return <Dashboard 
          activeChatMessages={activeChatMessages}
          isChatLoading={isChatLoading}
          onSendMessage={handleSendMessage}
          onNewConversation={handleNewConversation}
          brandVoiceProfile={brandVoiceProfile}
          onSaveBrandVoice={handleSaveBrandVoice}
        />;
      case 'multimedia':
        return <MultimediaCreator />;
      default:
        return <Dashboard 
          activeChatMessages={activeChatMessages}
          isChatLoading={isChatLoading}
          onSendMessage={handleSendMessage}
          onNewConversation={handleNewConversation}
          brandVoiceProfile={brandVoiceProfile}
          onSaveBrandVoice={handleSaveBrandVoice}
        />;
    }
  };

  if (isLoading) {
    return <Intro />;
  }

  return (
    <div className={`min-h-screen ${mainBgClass} transition-colors duration-300`}>
      <Header 
        activeView={activeView} 
        setActiveView={setActiveView}
        conversations={conversations}
        activeConversationId={activeConversationId}
        onSelectConversation={handleSelectConversation}
        onNewConversation={handleNewConversation}
        onDeleteConversation={handleDeleteConversation}
      />
      <main className="pt-28 pb-8 px-4 sm:px-8">
        {renderActiveView()}
      </main>
      <ChatBot />
    </div>
  );
};

export default App;
