const DEFAULT_USER_PROFILE: XUserProfile = {
  id: 'default-user',
  name: 'Tu Nombre',
  handle: '@tu_usuario',
  avatarUrl: `data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%2394A3B8'%3E%3Cpath d='M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z'/%3E%3C/svg%3E`,
  verified: false
};

interface DashboardProps {
  activeChatMessages: ChatMessage[];
  isChatLoading: boolean;
  onSendMessage: (message: string, file?: { data: string; mimeType: string; name: string }) => Promise<string[]>;
  onNewConversation: () => void;
  brandVoiceProfile: BrandVoiceProfile | null;
  onSaveBrandVoice: (profile: BrandVoiceProfile) => void;
}

const fileToBlob = (file: File): Promise<{data: string, mimeType: string, name: string}> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            // Basic fallback for mime types if empty (e.g. windows/md files sometimes)
            let mimeType = file.type;
            if (!mimeType) {
                if (file.name.endsWith('.md')) mimeType = 'text/markdown';
                if (file.name.endsWith('.txt')) mimeType = 'text/plain';
                if (file.name.endsWith('.csv')) mimeType = 'text/csv';
                if (file.name.endsWith('.json')) mimeType = 'application/json';
            }
            resolve({ data: result.split(',')[1], mimeType, name: file.name });
        };
        reader.onerror = error => reject(error);
    });
}

const Dashboard: React.FC<DashboardProps> = ({ activeChatMessages, isChatLoading, onSendMessage, onNewConversation, brandVoiceProfile, onSaveBrandVoice }) => {
  const [tweets, setTweets] = useState<EditableTweet[]>([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  const [isLoading, setIsLoading] = useState(false);
  const [generationStatus, setGenerationStatus] = useState<{ title: string; steps: string[]; currentStep: number; error: string | null; } | null>(null);

  const [isBrandVoiceModalOpen, setIsBrandVoiceModalOpen] = useState(false);

  const [isMediaPromptModalOpen, setIsMediaPromptModalOpen] = useState(false);
  const [mediaPrompt, setMediaPrompt] = useState('');
  const [mediaAspectRatio, setMediaAspectRatio] = useState('16:9');
  const [mediaGenerationTarget, setMediaGenerationTarget] = useState<{type: 'image', index: number} | null>(null);
  const [apiError, setApiError] = useState<string | null>(null);

  const mediaFileInputRef = useRef<HTMLInputElement>(null);
  const [mediaTargetIndex, setMediaTargetIndex] = useState<number | null>(null);
  const tweetPreviewRefs = useRef<(HTMLDivElement | null)[]>([]);

  const effectiveUserProfile = DEFAULT_USER_PROFILE;

  const handleTweetChange = (index: number, value: string) => {
    const newTweets = [...tweets];
    newTweets[index].content = value;
    setTweets(newTweets);
  };

  const addTweetToThread = () => {
    setTweets([...tweets, { id: `tweet-${Date.now()}`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  };

    const handleNewCreation = () => {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
      onNewConversation();
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }) => {
    const parsedTweets = await onSendMessage(message, file);

    if (parsedTweets.length > 0) {
        setTweets(parsedTweets.map((content, i) => ({
            id: `tweet-${Date.now()}-${i}`,
            content,
            media: null,
            isLoadingMedia: false,
            isCopied: false,
            isRegenerating: false,
        })));
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setTweets(prevTweets => {
        const newTweets = [...prevTweets];
        newTweets[index] = {...newTweets[index], isCopied: true};
        return newTweets;
      });
      setTimeout(() => {
        setTweets(prevTweets => {
          const resetTweets = [...prevTweets];
          resetTweets[index] = {...resetTweets[index], isCopied: false};
          return resetTweets;
        });
      }, 2000);
    });
  };

  const handleRegenerateTweet = async (index: number) => {
    const originalTweet = tweets[index];
    if (!originalTweet || originalTweet.content.trim() === '') return;

    setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: true } : t));

    try {
        const regeneratedContent = await regenerateTweet(originalTweet.content);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, content: regeneratedContent, isRegenerating: false } : t));
    } catch (error) {
        console.error("Error al regenerar el tuit:", error);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: false } : t));
    }
  };

  const handleDeleteTweet = (index: number) => {
    if (tweets.length === 1) {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    } else {
      setTweets(prevTweets => prevTweets.filter((_, i) => i !== index));
    }
  };

    const closeMediaPromptModal = () => {
        setIsMediaPromptModalOpen(false);
        setMediaPrompt('');
        setMediaGenerationTarget(null);
    };

    const handleConfirmMediaGeneration = async () => {
        if (!mediaGenerationTarget || !mediaPrompt) return;

        const { index } = mediaGenerationTarget;
        closeMediaPromptModal();

        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: true } : t));
        try {
            const { images } = await generateImage(mediaPrompt, mediaAspectRatio);
            if (images.length > 0) {
                const mediaUrl = `data:image/jpeg;base64,${images[0]}`;
                setTweets(prev => prev.map((t, i) => i === index ? { ...t, media: { type: 'image', url: mediaUrl }, isLoadingMedia: false } : t));
            } else {
                throw new Error("La IA no generó una imagen.");
            }
        } catch (error) {
            const message = error instanceof Error ? error.message : "Error al generar la imagen. Por favor, inténtalo de nuevo.";
            setApiError(message);
            setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: false } : t));
        }
    };

    const handleGenerateMedia = async (index: number) => {
        const tweetContent = tweets[index]?.content;
        if (!tweetContent) {
            setApiError("Por favor, escribe algo en el tuit para generar una imagen.");
            return;
        }

        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: true } : t));
        try {
            const imagePrompt = await createImagePromptFromTweet(tweetContent);
            setMediaPrompt(imagePrompt);
            setMediaGenerationTarget({ type: 'image', index });
            setMediaAspectRatio('16:9'); // Default aspect ratio
            setIsMediaPromptModalOpen(true);
        } catch (error) {
            const message = error instanceof Error ? error.message : "Error al crear el prompt para la imagen. Por favor, inténtalo de nuevo.";
            setApiError(message);
        } finally {
            setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: false } : t));
        }
    };

  const handleUploadMedia = (index: number) => {
      setMediaTargetIndex(index);
      mediaFileInputRef.current?.click();
  };

  const handleFileSelectedForTweet = (event: React.ChangeEvent<HTMLInputElement>) => {
      if (mediaTargetIndex === null) return;
      const file = event.target.files?.[0];
      if (file) {
          const url = URL.createObjectURL(file);
          const type = file.type.startsWith('image') ? 'image' : 'video';
          setTweets(prev => prev.map((t, i) => i === mediaTargetIndex ? { ...t, media: { type, url } } : t));
      }
      setMediaTargetIndex(null);
      if (event.target) event.target.value = '';
  };


  const handleRemoveMedia = (index: number) => {
      setTweets(prev => prev.map((t, i) => i === index ? { ...t, media: null } : t));
  };

  return (
    <div className="max-w-[1400px] mx-auto">
       <input type="file" ref={mediaFileInputRef} onChange={handleFileSelectedForTweet} className="hidden" accept="image/*,video/*" />
       <BrandVoiceModal 
          isOpen={isBrandVoiceModalOpen}
          onClose={() => setIsBrandVoiceModalOpen(false)}
          onSave={onSaveBrandVoice}
        />
        {apiError && (
            <div className="fixed inset-0 bg-bg-primary/80 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-fade-in">
                <div className="bg-bg-secondary border border-border-primary rounded-xl p-6 w-full max-w-lg relative shadow-2xl shadow-black/50">
                    <h2 className="text-xl font-bold mb-4 text-danger">Error de Generación</h2>
                    <p className="text-sm text-text-secondary mb-4">
                      {apiError}
                    </p>
                    <div className="flex justify-end gap-3 mt-6">
                        <button onClick={() => setApiError(null)} className="px-6 py-2 rounded-full font-bold bg-slate-200 text-slate-800 hover:bg-slate-300 transition">Cerrar</button>
                    </div>
                </div>
            </div>
        )}
        {isMediaPromptModalOpen && (
            <div className="fixed inset-0 bg-bg-primary/80 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-fade-in">
                <div className="bg-bg-secondary border border-border-primary rounded-xl p-6 w-full max-w-lg relative shadow-2xl shadow-black/50">
                    <h2 className="text-xl font-bold mb-4">Generar Imagen</h2>
                    <p className="text-sm text-text-secondary mb-4">
                      Hemos creado un prompt de imagen sugerido basado en tu tuit. Puedes editarlo antes de generar.
                    </p>
                    <textarea
                        value={mediaPrompt}
                        onChange={(e) => setMediaPrompt(e.target.value)}
                        placeholder="Introduce un prompt para el medio..."
                        className="w-full bg-bg-primary border border-border-primary rounded-lg p-3 focus:ring-2 focus:ring-accent-primary focus:outline-none transition mb-4"
                        rows={4}
                    />

                     <div className="mb-4">
                        <label className="text-sm font-semibold text-text-secondary mb-2 block">Relación de Aspecto</label>
                        <div className="flex gap-2">
                            {['1:1', '16:9', '9:16', '4:3'].map(ratio => (
                                <button 
                                    key={ratio} 
                                    onClick={() => setMediaAspectRatio(ratio)}
                                    className={`px-3 py-1 rounded-full text-xs font-bold border transition-colors ${mediaAspectRatio === ratio ? 'bg-accent-primary text-white border-accent-primary' : 'bg-transparent text-text-secondary border-slate-600 hover:border-slate-400'}`}
                                >
                                    {ratio}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 mt-6">
                        <button onClick={closeMediaPromptModal} className="px-6 py-2 rounded-full font-bold bg-slate-200 text-slate-800 hover:bg-slate-300 transition">Cancelar</button>
                        <button onClick={handleConfirmMediaGeneration} disabled={!mediaPrompt} className="px-6 py-2 rounded-full font-bold bg-accent-primary text-white hover:opacity-90 transition disabled:opacity-50">Generar</button>
                    </div>
                </div>
            </div>
        )}
        {generationStatus && (
            <GenerationStatus
                title={generationStatus.title}
                steps={generationStatus.steps}
                currentStepIndex={generationStatus.currentStep}
                error={generationStatus.error}
            />
        )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        <div className="bg-white text-slate-900 rounded-2xl border border-slate-200 shadow-xl flex flex-col h-[calc(100vh-9rem)] lg:sticky lg:top-28">
            <div className="flex items-center justify-between p-4 border-b border-slate-200 bg-slate-50 rounded-t-xl">
                 <h2 className="font-bold text-slate-700">Chat & Creación</h2>
                 <button onClick={() => setIsBrandVoiceModalOpen(true)} className="flex items-center gap-2 text-sm text-accent-primary font-bold hover:underline">
                    <SparklesIcon className="h-4 w-4" /> Voz de Marca
                 </button>
