          <div className="flex flex-col h-[calc(100vh-9rem)]">
            <div className="flex justify-between items-center flex-shrink-0">
              <h2 className="text-2xl font-bold text-slate-800">Vista Previa</h2>
              <button onClick={handleNewCreation} className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 rounded-full text-sm font-semibold text-brand-text-dark hover:bg-slate-100 shadow-sm">
                  <PlusIcon className="h-5 w-5" /> Nueva Creación
              </button>
            </div>
            <div className="space-y-4 flex-grow my-4 overflow-y-auto pr-2">
               {tweets.map((tweet, index) => (
                  <div key={tweet.id} ref={el => { tweetPreviewRefs.current[index] = el; }}>
                      <TweetPreview
                          tweet={{
                            id: tweet.id,
                            content: tweet.content,
