export const generateImage = async (prompt: string, aspectRatio: string = '1:1', referenceImages?: { data: string; mimeType: string }[]): Promise<{ images: string[], model: string }> => {
    const ai = getGeminiClient();

    const ratioMap: Record<string, string> = {
        '1:1': '1:1',
        '16:9': '16:9',
        '9:16': '9:16',
        '4:3': '4:3',
        '3:4': '3:4'
    };
    const validRatio = ratioMap[aspectRatio] || '1:1';

    let REFERENCE_BLOCK = "";
    if (referenceImages && referenceImages.length > 0) {
        REFERENCE_BLOCK = `
        [CRITICAL: REFERENCE IMAGE ENFORCEMENT]
        - Input image(s) provided.
        - MUST USE INPUT IMAGE(S) AS FOUNDATION.
        - PRESERVE FACIAL FEATURES, BONE STRUCTURE, AND IDENTITY EXACTLY.
        - This is a "Copy & Paste" of the subject, NOT a "Reimagining".
        `;
    }

    const textMatches = prompt.match(/["']([^"']+)["']|text\s+([a-zA-Z0-9\s]+)/i);
    let TEXT_BLOCK = `
    [TEXT RENDERING RULES]
    - TEXT MUST BE RENDERED EXACTLY AS WRITTEN. NO SPELLING ERRORS.
    - FONT: Clear, legible.
    `;

    if (textMatches) {
        const extractedText = textMatches[1] || textMatches[2];
        TEXT_BLOCK += `
        - REQUIRED TEXT: "${extractedText}"
        - ACTION: Paint this text into the image.
        `;
    }

    const QUALITY_BLOCK = `
    [VISUAL STYLE]
    - Output: 8K PHOTOREALISTIC RAW.
    - Camera: 85mm lens, f/1.8.
    - Skin Texture: Visible pores, sub-surface scattering. NO PLASTIC SKIN.
    `;

    const RATIO_BLOCK = `
    [TECHNICAL SPEC]
    - ASPECT RATIO: ${validRatio}
    - COMPOSITION: Fit within ${validRatio}.
    `;

    // CRITICAL FIX: The system instruction must explicitly forbid conversational text.
    // Gemini 2.0 Flash Exp is chatty. We force it to act as a renderer only.
    const finalPrompt = `
    *** SYSTEM OVERRIDE: IMAGE GENERATION MODE ***
    YOU ARE A NON-CONVERSATIONAL IMAGE GENERATION ENGINE.
    YOU DO NOT SPEAK. YOU DO NOT REPLY WITH TEXT.
    YOU ONLY OUTPUT THE GENERATED IMAGE DATA.
    IF YOU CANNOT GENERATE AN IMAGE, OUTPUT "ERROR_NO_IMAGE".

    ${REFERENCE_BLOCK}
    ${TEXT_BLOCK}
    ${QUALITY_BLOCK}
    ${RATIO_BLOCK}

    [USER REQUEST]: ${prompt}
    `;

    const parts: any[] = [];

    if (referenceImages && referenceImages.length > 0) {
        referenceImages.forEach(img => {
            parts.push({ inlineData: { data: img.data, mimeType: img.mimeType } });
        });
    }

    parts.push({ text: finalPrompt });

    try {
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: IMAGE_MODEL,
            contents: { parts },
        }));

        const images: string[] = [];
        if (response.candidates?.[0]?.content?.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    images.push(part.inlineData.data);
                }
            }
        }

        if (images.length > 0) return { images, model: 'Nanobanana' };

        // Fallback: Check if text response is actually an error or conversational refusal
        const textPart = response.candidates?.[0]?.content?.parts?.find(p => p.text)?.text;
        if (textPart) {
             console.warn("Gemini replied with text instead of image:", textPart);
             if (textPart.includes("ERROR_NO_IMAGE")) {
                 throw new Error("La IA no pudo generar la imagen con los parámetros dados.");
             }
             throw new Error(`La IA respondió con texto en lugar de imagen: ${textPart.substring(0, 100)}...`);
        }

        throw new Error("La IA no generó ninguna imagen válida.");

    } catch (error) {
            handleGenerationError(error, 'imagen');
            return { images: [], model: 'Error' };
    }
};

