const fileToBlob = (file: File): Promise<{data: string, mimeType: string, name: string}> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            let mimeType = file.type;
            if (!mimeType) {
                if (file.name.endsWith('.md')) mimeType = 'text/markdown';
                if (file.name.endsWith('.txt')) mimeType = 'text/plain';
                if (file.name.endsWith('.csv')) mimeType = 'text/csv';
                if (file.name.endsWith('.json')) mimeType = 'application/json';
            }
            resolve({ data: result.split(',')[1], mimeType, name: file.name });
        };
        reader.onerror = error => reject(error);
    });
}

