import { GoogleGenAI, Type, GenerateContentResponse, Chat, Modality, GenerateImagesResponse, Operation } from "@google/genai";
import type { Source, Tweet, BrandVoiceProfile, TrendingTopic, XUserProfile } from "../types";

// Helper to get a Gemini client instance
const getGeminiClient = () => {
    // API Key is injected by the execution environment.
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("Gemini API key is not configured in the environment.");
    }
    return new GoogleGenAI({ apiKey });
};

/**
 * A wrapper function to add retry logic with exponential backoff to API calls.
 */
export const withRetry = async <T>(apiCall: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
    for (let i = 0; i < retries; i++) {
        try {
            return await apiCall();
        } catch (error) {
            const isLastAttempt = i === retries - 1;
            const errorMessage = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();
            const isRetryable = errorMessage.includes("xhr error") || 
                                errorMessage.includes("rpc failed") || 
                                errorMessage.includes("500") ||
                                errorMessage.includes("429") || 
                                errorMessage.includes("rate-limited") || 
                                errorMessage.includes("at capacity");

            // Don't retry on permission denied (403) or not found (404) as they are likely permanent config issues
            if ((errorMessage.includes("permission denied") || errorMessage.includes("403") || errorMessage.includes("not found") || errorMessage.includes("404")) && !isLastAttempt) {
                 throw error; 
            }

            if (isRetryable && !isLastAttempt) {
                console.warn(`API call failed (attempt ${i + 1}/${retries}). Retrying in ${delay}ms...`, error);
                await new Promise(res => setTimeout(res, delay));
                delay *= 2; 
            } else {
                throw error; 
            }
        }
    }
    throw new Error("API call failed after all retries.");
};


interface FilePart {
    mimeType: string;
    data: string; // base64 encoded
