export const generateImage = async (prompt: string, aspectRatio: string = '1:1', referenceImages?: { data: string; mimeType: string }[]): Promise<{ images: string[], model: string }> => {
    const ai = getGeminiClient();

    const ratioMap: Record<string, string> = {
        '1:1': '1:1',
        '16:9': '16:9',
        '9:16': '9:16',
        '4:3': '4:3',
        '3:4': '3:4'
    };
    const validRatio = ratioMap[aspectRatio] || '1:1';

    // Construct the prompt parts
    let REFERENCE_BLOCK = "";
    if (referenceImages && referenceImages.length > 0) {
        REFERENCE_BLOCK = `
        [STRICT REFERENCE MODE]
        - Use the attached image(s) as the absolute visual foundation.
        - Preserve identity, facial features, and key object details exactly.
        - Do not reimagine the subject; adapt it to the new context.
        `;
    }

    const textMatches = prompt.match(/["']([^"']+)["']|text\s+([a-zA-Z0-9\s]+)/i);
    let TEXT_BLOCK = "";
    if (textMatches) {
        const extractedText = textMatches[1] || textMatches[2];
        TEXT_BLOCK = `
        [TEXT INSTRUCTION]
        - RENDER TEXT: "${extractedText}"
        - Ensure perfect spelling.
        `;
    }

    const finalPrompt = `
    *** IMAGE GENERATION REQUEST ***
    I need you to generate a photorealistic image based on the following description.

    CRITICAL INSTRUCTION:
    - DO NOT reply with conversational text like "Here is the image" or "Okay".
    - DO NOT provide explanations.
    - JUST generate the image.
    - If you strictly cannot generate an image, reply with "ERROR_NO_IMAGE".

    ${REFERENCE_BLOCK}
    ${TEXT_BLOCK}

    Technical Specs:
    - Style: 8K Photorealistic RAW
    - Aspect Ratio: ${validRatio}

    Prompt: ${prompt}
    `;

    const parts: any[] = [];
    if (referenceImages && referenceImages.length > 0) {
        referenceImages.forEach(img => {
            parts.push({ inlineData: { data: img.data, mimeType: img.mimeType } });
        });
    }
    parts.push({ text: finalPrompt });

    try {
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: IMAGE_MODEL_PRIMARY,
            contents: { parts },
        }));

        const images: string[] = [];
        if (response.candidates?.[0]?.content?.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    images.push(part.inlineData.data);
                }
            }
        }

        if (images.length > 0) return { images, model: 'TwixAi Gen 2.0' }; 

        // Check for text refusal/hallucination
        const textPart = response.candidates?.[0]?.content?.parts?.find(p => p.text)?.text;
        if (textPart) {
            console.warn(`Model returned text instead of image:`, textPart);
            if (textPart.includes("ERROR_NO_IMAGE")) {
                 throw new Error("La IA no pudo generar la imagen con los parámetros dados.");
            }
            throw new Error(`La IA respondió con texto en lugar de imagen: ${textPart.substring(0, 100)}... Intenta simplificar el prompt.`);
        }

        throw new Error("La IA no generó ninguna imagen válida.");

    } catch (error) {
        handleGenerationError(error, 'imagen');
        return { images: [], model: 'Error' };
    }
};

export const editImage = async (images: { data: string; mimeType: string }[], prompt: string, aspectRatio: string = '1:1'): Promise<{ image?: { data: string; mimeType: string }, text?: string, model: string }> => {
    try {
        const { images: resultImages } = await generateImage(prompt, aspectRatio, images);
        if (resultImages.length > 0) {
            return { 
                image: { data: resultImages[0], mimeType: 'image/jpeg' }, 
                model: 'TwixAi Gen 2.0' 
            };
        }
        throw new Error("Failed to edit image");
    } catch (e) {
        throw e;
    }
};

export const generateVideo = async (prompt: string, aspectRatio: string = '16:9', onProgress?: (status: string) => void): Promise<string> => {
     try {
        const ai = getGeminiClient();
        onProgress?.('🤖 Iniciando Veo...');

        let validAspectRatio = aspectRatio;
        if (aspectRatio !== '16:9' && aspectRatio !== '9:16') {
             validAspectRatio = '16:9'; 
        }

        let operation = await ai.models.generateVideos({
            model: 'veo-3.1-fast-generate-preview',
            prompt: prompt,
            config: {
                numberOfVideos: 1,
                aspectRatio: validAspectRatio as any,
                resolution: '720p'
            }
        });

        onProgress?.('⏳ Procesando con IA...');

        while (!operation.done) {
            await new Promise(resolve => setTimeout(resolve, 5000));
            operation = await ai.operations.getVideosOperation({operation: operation});
            onProgress?.('⏳ Renderizando...');
        }

        const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
        if (!videoUri) throw new Error("No se generó la URI del video.");

        const response = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
        const blob = await response.blob();

        onProgress?.('🎉 ¡Listo!');
        return URL.createObjectURL(blob);

    } catch (error) {
        handleGenerationError(error, 'video');
        return '';
    }
}


